import javax.naming.Context;
import javax.naming.NamingEnumeration;
import javax.naming.directory.DirContext;
import javax.naming.directory.InitialDirContext;
import javax.naming.directory.SearchControls;
import javax.naming.directory.SearchResult;
import java.util.HashMap;
import java.util.Map;

public class LDAPUserSearcher {

    public static Map<String, String> searchUser(String username) throws Exception {
        Context ctx = new InitialDirContext();
        SearchControls controls = new SearchControls();
        controls.setSearchScope(SearchControls.SUBTREE_SCOPE);
        String[] attributes = {"mail", "displayName", "department"};
        controls.setReturningAttributes(attributes);
        String filter = "uid=" + username;
        NamingEnumeration<SearchResult> results = ctx.search("", filter, controls);

        if (results.hasMore()) {
            SearchResult result = results.next();
            Map<String, String> user = new HashMap<>();
            for (String attribute : attributes) {
                user.put(attribute, (String) result.getAttributes().get(attribute).get());
            }
            return user;
        } else {
            return null;
        }
    }
}